SELECT SUM(infants_given_all_vaccines) AS total_vaccinated_infants
FROM child_immunization
WHERE region_id = 1;

SELECT total_pregnant_women, total_live_births
FROM maternal_health
WHERE total_live_births > 100;

SELECT region_id, SUM(infants_given_all_vaccines) AS total_infants_vaccinated
FROM child_immunization
GROUP BY region_id;

SELECT total_sterilisation_conducted
FROM family_planning
WHERE region_id = 1;

SELECT AVG(healthcare_facilities) AS avg_facilities
FROM regions
WHERE population = (SELECT MAX(population) FROM regions);
